from typing import Any

# Tool name allowlists per role. Explicit deny-by-default.
ROLE_PERMISSIONS: dict[str, frozenset[str]] = {
    "read_only": frozenset({
        "get_customer", "list_orders", "get_order",
        "search_knowledge_base", "get_product",
    }),
    "support": frozenset({
        "get_customer", "list_orders", "get_order",
        "search_knowledge_base", "get_product",
        "update_ticket_status", "add_ticket_note",
        "send_customer_email",
    }),
    "billing": frozenset({
        "get_customer", "list_orders", "get_order",
        "get_invoice", "list_invoices",
        "create_refund", "apply_credit", "void_invoice",
    }),
    "admin": None,   # None = unrestricted
}

def is_permitted(tool_name: str, role: str) -> bool:
    allowed = ROLE_PERMISSIONS.get(role)
    if allowed is None:
        return True   # admin
    return tool_name in allowed

def dispatch(
    tool_name: str,
    inputs: dict[str, Any],
    role: str,
    registry,
) -> dict[str, Any]:
    if not is_permitted(tool_name, role):
        return {
            "error": "PERMISSION_DENIED",
            "message": f"Role '{role}' is not permitted to call '{tool_name}'",
        }
    tool_def = registry.get(tool_name)
    if tool_def is None:
        return {"error": "NOT_FOUND", "message": f"Tool '{tool_name}' not found"}
    return tool_def.handler(**inputs)

from dataclasses import dataclass

@dataclass(frozen=True)
class SessionContext:
    user_id: str
    role: str
    tenant_id: str
    # Optional resource-level allowlist (None = all resources for this tenant)
    allowed_customer_ids: frozenset[str] | None = None

def get_customer_scoped(
    customer_id: str,
    ctx: SessionContext,
) -> dict[str, Any]:
    """Fetch a customer — scoped to the session's tenant."""
    # Scope check before any external call
    if ctx.allowed_customer_ids is not None:
        if customer_id not in ctx.allowed_customer_ids:
            return {
                "error": "PERMISSION_DENIED",
                "message": "This session is not permitted to access that customer",
            }

    # Inject tenant_id into the query so the backend enforces row-level isolation
    resp = _SESSION.get(
        f"{_INTERNAL_BASE}/customers/{customer_id}",
        params={"tenant_id": ctx.tenant_id},
        timeout=8,
    )
    if resp.status_code == 404:
        return {"error": "NOT_FOUND", "message": f"Customer {customer_id} not found"}
    if not resp.ok:
        return {"error": "SERVICE_UNAVAILABLE", "message": str(resp.status_code)}
    c = resp.json()
    # Verify tenant matches — defence-in-depth even if backend enforces it
    if c.get("tenant_id") != ctx.tenant_id:
        return {"error": "PERMISSION_DENIED", "message": "Tenant mismatch"}
    return {"customer_id": c["id"], "name": c["name"], "status": c["status"]}

import pytest
from mytools.permissions import full_dispatch, SessionContext
from mytools.registry import ToolRegistry, ToolDef

@pytest.fixture
def reg():
    r = ToolRegistry()
    r.register(ToolDef(
        name="create_refund",
        description="Issue a refund.",
        input_schema={"type":"object","properties":{"order_id":{"type":"string"}}},
        handler=lambda order_id, ctx: {"refunded": True, "order_id": order_id},
        tags=["billing"],
    ))
    return r

def support_ctx():
    return SessionContext(user_id="u1", role="support", tenant_id="t1")

def billing_ctx():
    return SessionContext(user_id="u2", role="billing", tenant_id="t1")

def test_support_cannot_refund(reg):
    result = full_dispatch("create_refund", {"order_id": "o1"}, support_ctx(), reg)
    assert result["error"] == "PERMISSION_DENIED"

def test_billing_needs_confirmation(reg):
    result = full_dispatch("create_refund", {"order_id": "o1"}, billing_ctx(), reg)
    assert result["status"] == "PENDING_CONFIRMATION"

def test_billing_approved_executes(reg):
    result = full_dispatch(
        "create_refund", {"order_id": "o1"}, billing_ctx(), reg, approved=True
    )
    assert result == {"refunded": True, "order_id": "o1"}
